import chalk4 from "chalk";
import ora3 from "ora";
async function sessionsCommand(options, globalOpts) {
  const { config, isFirstRun } = ensureInit();
  const limit = options.all ? Infinity : parseInt(options.limit || "30", 10);
  let spinner = null;
  if (!isJsonMode() && !isQuietMode()) {
    spinner = ora3({
      text: chalk4.dim("  Scanning sessions..."),
      spinner: "dots",
      color: "cyan",
      stream: process.stderr
    }).start();
  }
  const projects = await discoverProjects(config.claudeDir);
  const stats = computeStats(projects);
  spinner?.stop();
  if (projects.length === 0) {
    if (isJsonMode()) {
      outputJson({ projects: [] });
      return;
    }
    console.log();
    console.log(chalk4.white("  No sessions found yet."));
    console.log(
      chalk4.dim("  Start a Claude Code session in any project, then come back!")
    );
    console.log();
    return;
  }
  const filteredProjects = options.project ? projects.filter(
    (p) => p.name.toLowerCase().includes(options.project.toLowerCase()) || p.path.toLowerCase().includes(options.project.toLowerCase())
  ) : projects;
  if (isJsonMode()) {
    const data = {
      projects: filteredProjects.map((p) => ({
        name: p.name,
        path: p.path,
        sessionCount: p.sessionCount,
        sessions: p.sessions.map(toSessionJson)
      }))
    };
    outputJson(data);
    return;
  }
  if (filteredProjects.length === 0) {
    console.log();
    console.log(
      chalk4.yellow("  No projects matching ") + chalk4.white(`"${options.project}"`)
    );
    console.log();
    console.log(chalk4.white("  Your projects:"));
    for (const p of projects) {
      console.log(
        chalk4.cyan(`    ${p.name}`) + chalk4.dim(` \u2014 ${p.sessionCount} session${p.sessionCount === 1 ? "" : "s"}`)
      );
    }
    console.log();
    console.log(
      chalk4.dim("  Try: ") + chalk4.cyan(`devlog sessions -p ${projects[0].name}`)
    );
    console.log();
    return;
  }
  console.log();
  console.log(
    chalk4.bold.cyan("  \u258C") + chalk4.bold.white(" All Sessions") + (options.project ? chalk4.dim(` matching "${options.project}"`) : "")
  );
  console.log(
    chalk4.dim(
      `    ${formatNumber(stats.totalProjects)} projects \xB7 ${formatNumber(stats.totalSessions)} conversations \xB7 ${formatNumber(stats.totalMessages)} messages`
    )
  );
  console.log();
  if (isFirstRun) {
    console.log(
      chalk4.dim("  Each project shows your Claude conversations, newest first.")
    );
    console.log(
      chalk4.dim("  Pick one with ") + chalk4.cyan("devlog show <number>") + chalk4.dim(" to see the full chat.")
    );
    console.log();
  }
  let displayedCount = 0;
  let sessionIndex = 0;
  for (const project of filteredProjects) {
    if (displayedCount >= limit) break;
    const sessionWord = project.sessionCount === 1 ? "session" : "sessions";
    console.log(
      chalk4.bold.white("  \u{1F4C1} " + project.name) + chalk4.dim(` \u2014 ${project.sessionCount} ${sessionWord}`)
    );
    console.log(chalk4.dim("     " + project.path));
    console.log();
    const sessionsToShow = project.sessions.slice(0, limit - displayedCount);
    for (const session of sessionsToShow) {
      sessionIndex++;
      renderSessionRow(session, sessionIndex);
      displayedCount++;
    }
    if (project.sessions.length > sessionsToShow.length) {
      const remaining = project.sessions.length - sessionsToShow.length;
      console.log(
        chalk4.dim(`     + ${remaining} more \u2014 use `) + chalk4.cyan("--all") + chalk4.dim(" to show all")
      );
      console.log();
    }
  }
  console.log(chalk4.dim("  " + "\u2500".repeat(60)));
  console.log();
  console.log(
    chalk4.dim("  ") + chalk4.cyan("devlog show 1") + chalk4.dim(" view most recent  \xB7  ") + chalk4.cyan("devlog sessions -p <name>") + chalk4.dim(" filter")
  );
  console.log();
}
function renderSessionRow(session, index) {
  const m = session.meta;
  const time = formatSmartTime(session.updatedAt);
  const preview = m.firstUserMessage ? truncate(m.firstUserMessage.replace(/\n/g, " ").trim(), 46) : chalk4.dim("(empty)");
  const indexStr = chalk4.dim(`${index}.`.padEnd(4));
  console.log(
    chalk4.dim("   ") + indexStr + chalk4.white(time.padEnd(16)) + chalk4.white(preview)
  );
  const turns = m.humanTurns + m.assistantTurns;
  const parts = [];
  parts.push(messageCountContext(turns));
  if (m.toolCalls > 0) parts.push(toolCountContext(m.toolCalls));
  if (m.filesReferenced.length > 0) parts.push(fileCountContext(m.filesReferenced.length));
  if (m.totalCostUSD > 0) parts.push(costWithContext(m.totalCostUSD));
  if (m.errorCount > 0) {
    parts.push(chalk4.red(`${m.errorCount} error${m.errorCount === 1 ? "" : "s"}`));
  }
  console.log(
    chalk4.dim("   ") + "    " + " ".repeat(16) + parts.join(chalk4.dim("  \xB7  "))
  );
  console.log();
}

